#include <unistd.h>

static unsigned int	count_distinct_factors(unsigned int n);
static unsigned int	count_factors(unsigned int n);
static unsigned int	count_factors_recursive(unsigned int n);
static unsigned int	count_factors_recursive_helper(unsigned int n,
			    unsigned int divisor);
static void		test_factors(void);

// Replace this comment with any global variable declarations.

/* 
 * Requires:
 *   The input "n" must be greater than 0.
 *   The input "divisor" must be greater than 1.
 *
 * Effects:
 *   Returns the number of factors of the input "n", considering possible
 *   factors beginning at "divisor".
 */
static unsigned int
count_factors_recursive_helper(unsigned int n, unsigned int divisor)
{
	if (n == 1) {
		return (0);
	}
	if ((n % divisor) == 0) {
		return (1 + count_factors_recursive_helper(n / divisor, divisor));
	}
	return (count_factors_recursive_helper(n, divisor + 1));
}

/* 
 * Requires:  
 *   The input "n" must be greater than 1.
 *
 * Effects: 
 *   Returns the number of factors of the input "n".
 */
static unsigned int
count_factors_recursive(unsigned int n)
{
	assert(n > 1);
	return (count_factors_recursive_helper(n, 2));
}

/* 
 * Requires:  
 *   The input "n" must be greater than 1.
 *
 * Effects: 
 *   Returns the number of factors of the input "n".
 */
static unsigned int
count_factors(unsigned int n)
{
	unsigned int count = 0;
	unsigned int divisor = 2;

	assert(n > 1);
	while (n > 1) {
		if ((n % divisor) == 0) {
			n /= divisor;
			count += 1;
		} else {
			divisor += 1;
		}
	}

	return (count);
}

/* 
 * Requires:  
 *   The input "n" must be greater than 1.
 *
 * Effects: 
 *   Returns the number of distinct factors of the input "n".
 */
static unsigned int
count_distinct_factors(unsigned int n)
{
	unsigned int count = 0;
	unsigned int divisor = 2;

	assert(n > 1);
	while (n > 1) {
		if ((n % divisor) == 0) {
			count += 1;
			while ((n % divisor) == 0) {
				n /= divisor;
			}
		}
		divisor += 1;
	}

	return (count);
}

